#!/usr/bin/env python3
"""
encode-real-model.py — Encode a real HF causal-LM into GKQ v2.

Replaces the random-bytes synthetic generator in quantize-model-weights.py.
Loads a HuggingFace transformers model on CPU, walks its state_dict, applies
SVD-based spectral compression to all "spectral" tensors (Q/K/V/O, FFN
gate/up/down) and writes the rest (norms, embeddings, biases, lm_head) as
dense blocks. Output is a self-contained GKQ v2 file consumable by
inference-server-gkq.py and (eventually) fat-station's GkqBackend.

Usage:
    python3 encode-real-model.py --model Qwen/Qwen2.5-0.5B-Instruct \
        --output rknots/qwen-gkq.knot
    python3 encode-real-model.py --model ./local-hf-dir --output out.knot \
        --max-layers 4   # encode only first N transformer blocks (fast iteration)

Synthetic mode (no HF download / no transformers required):
    python3 encode-real-model.py --synthetic --output rknots/test-synth-gkq.knot \
        --syn-layers 3 --syn-hidden 128 --syn-ffn 256
"""

from __future__ import annotations

import argparse
import io
import os
import re
import sys
import tempfile
from pathlib import Path
from typing import Dict, List, Optional, Tuple

import numpy as np
from sklearn.utils.extmath import randomized_svd

# Local helpers.
_HERE = Path(__file__).resolve().parent
sys.path.insert(0, str(_HERE))
import gkq_v2_format as gkq  # noqa: E402
import sketch_knot_format as skf  # noqa: E402


# ─────────────────────────────────────────────────────────────────────────────
# SVD + uint8 quantization is now inlined in `_spectral_quantize` below so the
# rank is fully configurable. The legacy `quantize-model-weights.py` helpers
# (which hardcoded k=3 and padded) are no longer in this code path.
#
# SVD kernel: sklearn's randomized_svd (Halko et al. 2009). Full SVD scales
# as O(d_out * d_in * min(d_out, d_in)); randomized scales as
# O(d_out * d_in * rank), so for rank<<min(shape) — e.g. rank=64 on a
# Llama-70B 4096x14336 FFN — the speedup is ~min(shape)/rank ≈ 64x per
# tensor. Wall-clock: Gemma4-31B drops from ~14h to ~30 min, Llama-70B
# from ~5-6 days to ~3 hours. Output is no longer byte-identical to the
# old full-SVD encode (randomized SVD is approximate), but reconstruction
# error stays within Halko's bound — empirically <5% of the full-SVD
# baseline on Qwen2.5-0.5B rank-64.
# ─────────────────────────────────────────────────────────────────────────────


# ─────────────────────────────────────────────────────────────────────────────
# Name mapping HF → canonical GKQ names
# ─────────────────────────────────────────────────────────────────────────────

_LAYER_PREFIX = r"^model(?:\.language_model)?\.layers\.(\d+)\."

# Spectral tensors (weight matrices we SVD-compress).
_SPECTRAL_PATTERNS = [
    (re.compile(_LAYER_PREFIX + r"self_attn\.q_proj\.weight$"), "blk.{n}.attn_q.weight"),
    (re.compile(_LAYER_PREFIX + r"self_attn\.k_proj\.weight$"), "blk.{n}.attn_k.weight"),
    (re.compile(_LAYER_PREFIX + r"self_attn\.v_proj\.weight$"), "blk.{n}.attn_v.weight"),
    (re.compile(_LAYER_PREFIX + r"self_attn\.o_proj\.weight$"), "blk.{n}.attn_o.weight"),
    (re.compile(_LAYER_PREFIX + r"mlp\.gate_proj\.weight$"), "blk.{n}.ffn_gate.weight"),
    (re.compile(_LAYER_PREFIX + r"mlp\.up_proj\.weight$"), "blk.{n}.ffn_up.weight"),
    (re.compile(_LAYER_PREFIX + r"mlp\.down_proj\.weight$"), "blk.{n}.ffn_down.weight"),
]

# Dense tensors (kept raw — norms, biases, embeddings, lm_head, etc.).
_DENSE_PATTERNS = [
    (re.compile(_LAYER_PREFIX + r"input_layernorm\.weight$"), "blk.{n}.attn_norm.weight"),
    (re.compile(_LAYER_PREFIX + r"post_attention_layernorm\.weight$"), "blk.{n}.ffn_norm.weight"),
    (re.compile(_LAYER_PREFIX + r"self_attn\.q_proj\.bias$"), "blk.{n}.attn_q.bias"),
    (re.compile(_LAYER_PREFIX + r"self_attn\.k_proj\.bias$"), "blk.{n}.attn_k.bias"),
    (re.compile(_LAYER_PREFIX + r"self_attn\.v_proj\.bias$"), "blk.{n}.attn_v.bias"),
    (re.compile(_LAYER_PREFIX + r"self_attn\.o_proj\.bias$"), "blk.{n}.attn_o.bias"),
    (re.compile(_LAYER_PREFIX + r"mlp\.gate_proj\.bias$"), "blk.{n}.ffn_gate.bias"),
    (re.compile(_LAYER_PREFIX + r"mlp\.up_proj\.bias$"), "blk.{n}.ffn_up.bias"),
    (re.compile(_LAYER_PREFIX + r"mlp\.down_proj\.bias$"), "blk.{n}.ffn_down.bias"),
    # Gemma3-style extra norms (q_norm / k_norm) — keep as dense.
    (re.compile(_LAYER_PREFIX + r"self_attn\.q_norm\.weight$"), "blk.{n}.attn_q_norm.weight"),
    (re.compile(_LAYER_PREFIX + r"self_attn\.k_norm\.weight$"), "blk.{n}.attn_k_norm.weight"),
    (re.compile(_LAYER_PREFIX + r"pre_feedforward_layernorm\.weight$"), "blk.{n}.ffn_pre_norm.weight"),
    (re.compile(_LAYER_PREFIX + r"post_feedforward_layernorm\.weight$"), "blk.{n}.ffn_post_norm.weight"),
]

_DENSE_GLOBALS = {
    "model.embed_tokens.weight": "token_embd.weight",
    "model.language_model.embed_tokens.weight": "token_embd.weight",
    "model.norm.weight": "output_norm.weight",
    "model.language_model.norm.weight": "output_norm.weight",
    "lm_head.weight": "output.weight",
    "model.lm_head.weight": "output.weight",
}


def map_tensor_name(hf_name: str, max_layers: Optional[int]) -> Optional[Tuple[str, str]]:
    """Map an HF state_dict key to (canonical_name, kind in {"spectral","dense"}).

    Returns None if the tensor should be skipped (e.g. layer beyond --max-layers).
    """
    # Normalise VLM wrapper namespaces to standard model.* paths so existing
    # patterns match without modification.
    # Gemma4: model.language_model.layers.N.* → model.layers.N.*
    # Other VLMs: language_model.model.* → model.*, text_model.* → model.*
    if hf_name.startswith("model.language_model."):
        hf_name = "model." + hf_name[len("model.language_model."):]
    elif hf_name.startswith("language_model.model."):
        hf_name = hf_name[len("language_model."):]
    elif hf_name.startswith("language_model."):
        hf_name = "model." + hf_name[len("language_model."):]
    elif hf_name.startswith("text_model."):
        hf_name = "model." + hf_name[len("text_model."):]

    # Globals.
    if hf_name in _DENSE_GLOBALS:
        return (_DENSE_GLOBALS[hf_name], "dense")

    for pat, fmt in _SPECTRAL_PATTERNS:
        m = pat.match(hf_name)
        if m:
            n = int(m.group(1))
            if max_layers is not None and n >= max_layers:
                return None
            return (fmt.format(n=n), "spectral")

    for pat, fmt in _DENSE_PATTERNS:
        m = pat.match(hf_name)
        if m:
            n = int(m.group(1))
            if max_layers is not None and n >= max_layers:
                return None
            return (fmt.format(n=n), "dense")

    # Unknown: write as dense with the verbatim HF name to keep things lossless.
    return (hf_name, "dense")


# ─────────────────────────────────────────────────────────────────────────────
# Arch detection + KnotConfig dict construction
# ─────────────────────────────────────────────────────────────────────────────


def detect_arch(hf_config) -> str:
    archs = getattr(hf_config, "architectures", None) or []
    first = (archs[0] if archs else "").lower()
    mtype = (getattr(hf_config, "model_type", "") or "").lower()
    candidates = [first, mtype]
    for s in candidates:
        if "qwen2" in s or s == "qwen":
            return "qwen2"
        if "gemma4" in s:
            return "gemma4"
        if "gemma3" in s:
            return "gemma3"
        if "gemma" in s:
            return "gemma3"
        if "llama" in s:
            return "llama"
        if "mistral" in s:
            return "mistral"
        if "phi" in s:
            return "phi"
    return "qwen2"


def _config_get(config, key: str, default=None):
    if isinstance(config, dict):
        return config.get(key, default)
    return getattr(config, key, default)


def _config_get_from(primary, fallback, key: str, default=None):
    value = _config_get(primary, key, None) if primary is not None else None
    if value is not None:
        return value
    return _config_get(fallback, key, default)


def build_knot_config(hf_config, arch: str, max_layers: Optional[int]) -> dict:
    """Extract a KnotConfig-shaped dict from an HF config object."""
    # VLMs (Gemma4, LLaVA, etc.) nest text dims under text_config; fall back to
    # the top-level config per-key for hybrids that only nest some fields.
    text_config = _config_get(hf_config, "text_config", None)
    source_config = text_config or hf_config
    num_layers_full = int(_config_get_from(source_config, hf_config, "num_hidden_layers", 0))
    num_layers = min(num_layers_full, max_layers) if max_layers else num_layers_full
    hidden_dim = int(_config_get_from(source_config, hf_config, "hidden_size", 0))
    num_heads = int(_config_get_from(source_config, hf_config, "num_attention_heads", 0))
    num_kv_heads = int(_config_get_from(source_config, hf_config, "num_key_value_heads", num_heads))
    head_dim_attr = _config_get_from(source_config, hf_config, "head_dim", None)
    head_dim = int(head_dim_attr) if head_dim_attr else (hidden_dim // num_heads if num_heads else 0)
    intermediate_size = int(_config_get_from(source_config, hf_config, "intermediate_size", 0))
    vocab_size = int(_config_get_from(source_config, hf_config, "vocab_size", 0))
    rms_norm_eps = float(_config_get_from(source_config, hf_config, "rms_norm_eps", 1e-6))
    rope_theta = float(_config_get_from(source_config, hf_config, "rope_theta", 10000.0))

    cfg = {
        "arch": arch,
        "hidden_dim": hidden_dim,
        "num_layers": num_layers,
        "num_heads": num_heads,
        "num_kv_heads": num_kv_heads,
        "head_dim": head_dim,
        "intermediate_size": intermediate_size,
        "vocab_size": vocab_size,
        "rms_norm_eps": rms_norm_eps,
        "rope_theta": rope_theta,
    }

    # Optional Gemma3-ish fields.
    for k in (
        "sliding_window",
        "query_pre_attn_scalar",
        "attn_logit_softcapping",
        "final_logit_softcapping",
        "tie_word_embeddings",
    ):
        v = _config_get_from(source_config, hf_config, k, None)
        if v is not None:
            try:
                cfg[k] = v.item() if hasattr(v, "item") else v
            except Exception:
                cfg[k] = v
    return cfg


# ─────────────────────────────────────────────────────────────────────────────
# Encoding
# ─────────────────────────────────────────────────────────────────────────────


# ─────────────────────────────────────────────────────────────────────────────
# Sketch-tensor selection (Phase A — Standing-Wave Mesh)
# ─────────────────────────────────────────────────────────────────────────────
# Sketch coverage is broader than the spectral block: lm_head / token_embd are
# kept dense in the main GKQ v2 file (loss-sensitive), but we DO want a rank-K
# sketch of them because they're the highest-bandwidth tensors at serving
# time. We sketch every 2D weight matrix whose canonical name matches one of
# the prefixes below, and skip everything else (norms, biases, 1D tensors).

_SKETCH_NAME_PATTERNS = [
    re.compile(r"^blk\.\d+\.attn_[qkvo]\.weight$"),
    re.compile(r"^blk\.\d+\.ffn_(gate|up|down)\.weight$"),
    re.compile(r"^token_embd\.weight$"),
    re.compile(r"^output\.weight$"),
]


def _should_sketch(canonical_name: str) -> bool:
    return any(p.match(canonical_name) for p in _SKETCH_NAME_PATTERNS)


def _sketch_quantize(weight_2d: np.ndarray, rank: int):
    """Rank-K SVD + uint8 quantize for the sketches.knot artifact.

    Returns a `skf.SketchEntry`. Always uses sklearn's randomized_svd for the
    sketch rank (typically 16-32) — this is the rank ≪ min(shape) regime
    where randomized SVD is at its most favourable.
    """
    d_out, d_in = weight_2d.shape
    k = int(min(rank, d_out, d_in))
    weight_2d_f32 = weight_2d.astype(np.float32, copy=False)
    if k >= min(d_out, d_in):
        U_full, sigma_full, Vt_full = np.linalg.svd(weight_2d_f32, full_matrices=False)
        U = U_full[:, :k]
        sigma = sigma_full[:k]
        Vt = Vt_full[:k, :]
    else:
        U, sigma, Vt = randomized_svd(
            weight_2d_f32,
            n_components=k,
            n_oversamples=10,
            n_iter="auto",
            random_state=0,
        )
    u_q8, sigma_q8, v_q8, u_max, sigma_max, v_max = skf.quantize_sketch(U, sigma, Vt)
    return skf.SketchEntry(
        name="",  # caller assigns
        d_out=d_out, d_in=d_in, rank=k,
        u_q8=u_q8, sigma_q8=sigma_q8, v_q8=v_q8,
        u_max=u_max, sigma_max=sigma_max, v_max=v_max,
    )


def _spectral_quantize(weight_2d: np.ndarray, rank: int):
    """Run truncated SVD at exact target rank + uint8 max-scaled quantization.

    Replaces the old quantize-model-weights pathway (which hardcoded k=3 and
    padded). We need the configurable rank to land at rank≈64 for usable LLM
    reconstruction; the helper here is intentionally self-contained so it
    doesn't get reverted by callers expecting the legacy 3-component shape.

    Returns (u_q8, sigma_q8, v_q8, u_max, sigma_max, v_max, d_out, d_in, rel_err, effective_rank).

    `effective_rank` is min(rank, d_out, d_in) — what was actually retained.
    """
    d_out, d_in = weight_2d.shape
    k = int(min(rank, d_out, d_in))

    # Randomized SVD is O(d_out * d_in * rank) vs full SVD's
    # O(d_out * d_in * min(d_out, d_in)); for rank=64 on a 4096x14336 FFN
    # tensor that's ~64x per tensor (Halko et al. 2009). The full
    # decomposition only beats it when `rank` is close to min(shape), so
    # we fall back to np.linalg.svd whenever the target rank already
    # covers the matrix (also: randomized_svd assumes rank < min dim).
    weight_2d_f32 = weight_2d.astype(np.float32)
    if k >= min(d_out, d_in):
        U_full, sigma_full, Vt_full = np.linalg.svd(weight_2d_f32, full_matrices=False)
        U = U_full[:, :k]
        sigma = sigma_full[:k]
        Vt = Vt_full[:k, :]
    else:
        U, sigma, Vt = randomized_svd(
            weight_2d_f32,
            n_components=k,
            n_oversamples=10,        # default; bumps numerical stability
            n_iter="auto",           # power iterations for slow-decay spectra
            random_state=0,          # reproducibility for byte-identical comparisons
        )

    # Reconstruction error at the truncated rank (pre-quantization).
    W_recon = (U * sigma[np.newaxis, :]) @ Vt
    denom = float(np.linalg.norm(weight_2d, "fro")) + 1e-12
    rel_err = float(np.linalg.norm(weight_2d - W_recon, "fro") / denom)

    # uint8 max-scaled quantization. Three f32 scales per tensor.
    # U and Vt carry SIGNED values (orthonormal SVD factors have negatives);
    # we encode them as offset-128 signed-uint8: q = round((x/max) * 127) + 128.
    # sigma is non-negative; encoded as unsigned: q = round((x/max) * 255).
    # Decoder must mirror this: see gkq.reconstruct_spectral.
    u_max = float(np.abs(U).max() + 1e-10)
    sigma_max = float(np.abs(sigma).max() + 1e-10)
    v_max = float(np.abs(Vt).max() + 1e-10)

    u_q8 = np.clip(np.round((U / u_max) * 127.0) + 128.0, 0, 255).astype(np.uint8)
    sigma_q8 = np.clip(np.round((sigma / sigma_max) * 255.0), 0, 255).astype(np.uint8)
    v_q8 = np.clip(np.round((Vt / v_max) * 127.0) + 128.0, 0, 255).astype(np.uint8)

    return u_q8, sigma_q8, v_q8, u_max, sigma_max, v_max, d_out, d_in, rel_err, k


def _to_numpy(tensor) -> np.ndarray:
    """Convert a torch tensor (any dtype) to a numpy array safely (bf16 → f32)."""
    import torch  # local import to allow synthetic mode w/o torch

    t = tensor.detach().cpu()
    if t.dtype == torch.bfloat16:
        t = t.to(torch.float32)
    return t.numpy()


def encode_state_dict(
    items: List[Tuple[str, "np.ndarray | object"]],
    *,
    model_name: str,
    arch: str,
    knot_config: dict,
    output_path: str,
    max_layers: Optional[int],
    to_numpy=lambda x: x,
    tie_word_embeddings: bool = False,
    embed_key: str = "model.embed_tokens.weight",
    rank: int = gkq.RANK_DEFAULT,
    sketch_rank: Optional[int] = None,
    sketch_output_path: Optional[str] = None,
) -> dict:
    """Walk `items` (list of (hf_name, tensor)) and write GKQ v2.

    `to_numpy` is a callable applied lazily to each tensor (so caller can keep
    torch tensors and we only materialize numpy per-tensor).

    `rank` is the spectral rank to retain per tensor (default 64). Higher rank
    → bigger spectral block but much better reconstruction.

    Tied embeddings: when `tie_word_embeddings=True` and lm_head is absent
    from the state_dict, `output.weight` is written as a dense ALIAS to
    `token_embd.weight` (no payload duplication).

    Returns a summary dict.
    """
    # Two-pass: first classify all tensors so we can write accurate counts.
    classified: List[Tuple[str, str, object]] = []  # (canonical, kind, tensor)
    seen_canonical: Dict[str, Tuple[str, str]] = {}  # canonical → (hf_name, kind)
    aliases: List[Tuple[str, str]] = []  # (canonical_alias, canonical_target)

    # Detect storage-shared (tied) tensors by data_ptr where possible. HF
    # often stores lm_head.weight even when tied; both tensors share storage
    # and serializing both would duplicate ~545 MB for a 0.5B model.
    name_to_ptr: Dict[str, int] = {}

    def _tensor_data_ptr(t) -> Optional[int]:
        try:
            return int(t.data_ptr())
        except Exception:
            return None

    for hf_name, tensor in items:
        mapped = map_tensor_name(hf_name, max_layers)
        if mapped is None:
            continue
        canonical, kind = mapped
        if canonical in seen_canonical:
            # Skip duplicate (shouldn't happen normally).
            continue
        seen_canonical[canonical] = (hf_name, kind)
        ptr = _tensor_data_ptr(tensor)
        if ptr is not None:
            name_to_ptr[canonical] = ptr
        classified.append((canonical, kind, tensor))

    # Tied embeddings: prefer storage-sharing detection (works even when both
    # token_embd.weight and output.weight are in the HF state_dict, which is
    # the normal case for Qwen2.5). Fall back to the config flag when we have
    # no data_ptr info (numpy synthetic mode).
    def _emit_alias(alias_name: str, target_name: str, reason: str) -> bool:
        if alias_name not in seen_canonical or target_name not in seen_canonical:
            return False
        # Remove the duplicate from `classified` (writer will not emit a full block).
        before = len(classified)
        classified[:] = [(c, k, t) for c, k, t in classified if c != alias_name]
        if len(classified) < before:
            aliases.append((alias_name, target_name))
            print(f"[encode] tied weights ({reason}): aliasing {alias_name} → {target_name} "
                  f"(saves ~one copy of {target_name})")
            return True
        return False

    embed_ptr = name_to_ptr.get("token_embd.weight")
    out_ptr = name_to_ptr.get("output.weight")
    if embed_ptr is not None and out_ptr is not None and embed_ptr == out_ptr:
        _emit_alias("output.weight", "token_embd.weight", "shared data_ptr")
    elif tie_word_embeddings and "output.weight" not in seen_canonical and "token_embd.weight" in seen_canonical:
        # lm_head.weight absent from state_dict; emit alias so decoder still
        # sees output.weight.
        aliases.append(("output.weight", "token_embd.weight"))
        seen_canonical["output.weight"] = (embed_key, "dense")
        print(f"[encode] tied weights (config flag): aliasing output.weight → token_embd.weight")
    elif tie_word_embeddings and "output.weight" in seen_canonical and "token_embd.weight" in seen_canonical:
        # Storage may not match (e.g. numpy/synthetic), but the config says
        # they're tied — alias anyway.
        _emit_alias("output.weight", "token_embd.weight", "config flag")

    num_spectral = sum(1 for _, k, _ in classified if k == "spectral")
    num_dense = sum(1 for _, k, _ in classified if k == "dense") + len(aliases)
    print(f"[encode] classified {len(classified)} tensors: {num_spectral} spectral, "
          f"{num_dense - len(aliases)} dense + {len(aliases)} alias")
    print(f"[encode] spectral rank: {rank}")

    worst_err = 0.0
    worst_err_name = ""
    spectral_bytes = 0
    dense_bytes = 0
    out_path = Path(output_path)
    out_path.parent.mkdir(parents=True, exist_ok=True)

    with open(out_path, "wb") as f:
        gkq.write_header(f, model_name, arch, knot_config, num_spectral, num_dense)

        # Write spectral block first, then dense block (order matches the format spec).
        # Sort to keep deterministic output.
        spectral_items = sorted([(c, t) for c, k, t in classified if k == "spectral"], key=lambda x: x[0])
        dense_items = sorted([(c, t) for c, k, t in classified if k == "dense"], key=lambda x: x[0])

        for canonical, tensor in spectral_items:
            arr = to_numpy(tensor)
            arr = np.ascontiguousarray(arr, dtype=np.float32)
            if arr.ndim != 2:
                # Reshape to 2D if needed (rare; treat as [d_out, d_in]).
                arr = arr.reshape(arr.shape[0], -1)
            (u_q8, sigma_q8, v_q8, u_max, sigma_max, v_max,
             d_out, d_in, rel_err, eff_rank) = _spectral_quantize(arr, rank=rank)
            if rel_err > worst_err:
                worst_err = rel_err
                worst_err_name = canonical
            before = f.tell()
            gkq.write_spectral_tensor(
                f, canonical, u_q8, sigma_q8, v_q8,
                u_max, sigma_max, v_max, d_out, d_in, rank=eff_rank,
            )
            spectral_bytes += f.tell() - before

        # Dense non-alias blocks first so aliases written below resolve cleanly.
        for canonical, tensor in dense_items:
            arr = to_numpy(tensor)
            # Preserve f16; otherwise cast to f32. (HF most norms are f32.)
            if arr.dtype == np.float16:
                pass
            elif arr.dtype == np.float32:
                pass
            else:
                arr = arr.astype(np.float32)
            arr = np.ascontiguousarray(arr)
            before = f.tell()
            gkq.write_dense_tensor(f, canonical, arr)
            dense_bytes += f.tell() - before

        # Aliases (sorted for determinism).
        for alias_name, alias_target in sorted(aliases):
            before = f.tell()
            gkq.write_dense_alias(f, alias_name, alias_target)
            dense_bytes += f.tell() - before

    file_size = out_path.stat().st_size
    summary = {
        "output_path": str(out_path),
        "file_size_bytes": file_size,
        "file_size_mb": file_size / 1e6,
        "num_spectral": num_spectral,
        "num_dense": num_dense,
        "spectral_bytes": spectral_bytes,
        "dense_bytes": dense_bytes,
        "spectral_pct": 100.0 * spectral_bytes / max(file_size, 1),
        "dense_pct": 100.0 * dense_bytes / max(file_size, 1),
        "worst_reconstruction_error": worst_err,
        "worst_reconstruction_error_name": worst_err_name,
    }

    # ── Phase A: rank-K exclusion sketches ─────────────────────────────────
    # Side-car file `<output>.sketches.knot` with rank-K SVD sketches for
    # every 2D weight matrix worth sketching (lm_head, token_embd, all
    # attention/FFN projections). Always uses KNOT magic so fat-station's
    # existing mmap/HTTP loader can index it without changes.
    if sketch_rank is not None and sketch_rank > 0:
        if sketch_output_path is None:
            sketch_out = out_path.with_suffix(out_path.suffix + ".sketches.knot") \
                if out_path.suffix else out_path.with_name(out_path.name + ".sketches.knot")
        else:
            sketch_out = Path(sketch_output_path)
        sketch_out.parent.mkdir(parents=True, exist_ok=True)

        sketches: List[skf.SketchEntry] = []
        # Walk ALL classified tensors and sketch the ones matching the
        # SKETCH_NAME_PATTERNS (covers both spectral matrices and the dense
        # globals token_embd / output). Skip aliases — output.weight that
        # aliases token_embd.weight will sketch the same payload twice, but
        # cobordism wants them indexed under their canonical names anyway
        # (the sketch metadata is the wire artifact, not the underlying
        # storage).
        sketch_targets: List[Tuple[str, object]] = []
        for canonical, _kind, tensor in classified:
            if _should_sketch(canonical):
                sketch_targets.append((canonical, tensor))
        # Aliases too: if output.weight was aliased away above, re-sketch it
        # off the target tensor so cobordism sees a sketch for both names.
        alias_targets = dict(aliases)  # alias_name -> target_name
        target_to_tensor: Dict[str, object] = {c: t for c, _k, t in classified}
        for alias_name, target_name in aliases:
            if _should_sketch(alias_name) and target_name in target_to_tensor \
                    and alias_name not in [n for n, _ in sketch_targets]:
                sketch_targets.append((alias_name, target_to_tensor[target_name]))

        print(f"[sketch] generating rank-{sketch_rank} sketches for "
              f"{len(sketch_targets)} tensors → {sketch_out.name}")
        t_sketch_start = __import__("time").time()
        for canonical, tensor in sorted(sketch_targets, key=lambda x: x[0]):
            arr = to_numpy(tensor)
            arr = np.ascontiguousarray(arr, dtype=np.float32)
            if arr.ndim != 2:
                arr = arr.reshape(arr.shape[0], -1)
            entry = _sketch_quantize(arr, rank=int(sketch_rank))
            entry.name = canonical
            sketches.append(entry)

        sketch_summary = skf.write_sketches_knot(
            str(sketch_out),
            model_name=model_name,
            source_config=knot_config,
            sketches=sketches,
            sketch_rank_default=int(sketch_rank),
        )
        sketch_elapsed = __import__("time").time() - t_sketch_start
        sketch_summary["elapsed_sec"] = sketch_elapsed
        summary["sketches"] = sketch_summary
        print(f"[sketch] wrote {sketch_summary['file_size_mb']:.2f} MB "
              f"({sketch_summary['num_sketches']} sketches, "
              f"meta={sketch_summary['metadata_bytes']/1024:.1f} KB, "
              f"payload={sketch_summary['payload_bytes']/1e6:.2f} MB) "
              f"in {sketch_elapsed:.1f}s")

    return summary


def _print_summary(summary: dict) -> None:
    print("─" * 64)
    print(f"GKQ v2 file written: {summary['output_path']}")
    print(f"  size:               {summary['file_size_mb']:.2f} MB ({summary['file_size_bytes']:,} bytes)")
    print(f"  spectral tensors:   {summary['num_spectral']}  ({summary['spectral_pct']:.1f}% of file, {summary['spectral_bytes']:,} bytes)")
    print(f"  dense tensors:      {summary['num_dense']}  ({summary['dense_pct']:.1f}% of file, {summary['dense_bytes']:,} bytes)")
    print(f"  worst SVD rel-err:  {summary['worst_reconstruction_error']:.4f}  ({summary['worst_reconstruction_error_name']})")
    print("─" * 64)


# ─────────────────────────────────────────────────────────────────────────────
# HF mode
# ─────────────────────────────────────────────────────────────────────────────


def _encode_from_hf(args) -> dict:
    try:
        import torch
        from transformers import AutoConfig, AutoModelForCausalLM
    except Exception as e:  # pragma: no cover
        print(
            "ERROR: transformers/torch not available in this Python:\n"
            f"  {e}\n"
            "Install with one of:\n"
            "  pip3 install --user transformers torch safetensors\n"
            "  pip3 install --break-system-packages transformers torch safetensors\n"
            "  uv pip install --system transformers torch safetensors\n"
            "Or use --synthetic to skip the HF dependency.",
            file=sys.stderr,
        )
        raise

    print(f"[hf] loading model {args.model} on CPU…")
    model = AutoModelForCausalLM.from_pretrained(
        args.model, torch_dtype=torch.float32, device_map="cpu", low_cpu_mem_usage=True
    )
    hf_config = model.config
    arch = detect_arch(hf_config)
    knot_config = build_knot_config(hf_config, arch, args.max_layers)
    tie = bool(getattr(hf_config, "tie_word_embeddings", False))

    state = list(model.state_dict().items())
    print(f"[hf] state_dict has {len(state)} tensors; arch={arch}")

    summary = encode_state_dict(
        items=state,
        model_name=args.model_name or args.model,
        arch=arch,
        knot_config=knot_config,
        output_path=args.output,
        max_layers=args.max_layers,
        to_numpy=_to_numpy,
        tie_word_embeddings=tie,
        rank=args.rank,
        sketch_rank=args.with_exclusion_sketch,
        sketch_output_path=args.sketch_output,
    )
    return summary


# ─────────────────────────────────────────────────────────────────────────────
# Synthetic mode (no HF, no torch)
# ─────────────────────────────────────────────────────────────────────────────


def _make_synthetic_state(num_layers: int, hidden_dim: int, ffn_dim: int, num_heads: int = 4, vocab: int = 256):
    """Build a mock HF-style state_dict using only numpy.

    Tensors are small float32 arrays with mild structure so SVD has something
    meaningful to compress.
    """
    rng = np.random.default_rng(42)

    def rand(shape, scale=0.02, lowrank=True):
        if lowrank:
            r = max(1, min(shape) // 4)
            a = rng.standard_normal((shape[0], r)).astype(np.float32) * scale
            b = rng.standard_normal((r, shape[1])).astype(np.float32) * scale
            return a @ b
        return (rng.standard_normal(shape).astype(np.float32) * scale)

    items: List[Tuple[str, np.ndarray]] = []
    items.append(("model.embed_tokens.weight", rng.standard_normal((vocab, hidden_dim)).astype(np.float32) * 0.02))
    for i in range(num_layers):
        items.append((f"model.layers.{i}.input_layernorm.weight", np.ones((hidden_dim,), dtype=np.float32)))
        items.append((f"model.layers.{i}.self_attn.q_proj.weight", rand((hidden_dim, hidden_dim))))
        items.append((f"model.layers.{i}.self_attn.k_proj.weight", rand((hidden_dim, hidden_dim))))
        items.append((f"model.layers.{i}.self_attn.v_proj.weight", rand((hidden_dim, hidden_dim))))
        items.append((f"model.layers.{i}.self_attn.o_proj.weight", rand((hidden_dim, hidden_dim))))
        items.append((f"model.layers.{i}.self_attn.q_proj.bias", np.zeros((hidden_dim,), dtype=np.float32)))
        items.append((f"model.layers.{i}.self_attn.k_proj.bias", np.zeros((hidden_dim,), dtype=np.float32)))
        items.append((f"model.layers.{i}.self_attn.v_proj.bias", np.zeros((hidden_dim,), dtype=np.float32)))
        items.append((f"model.layers.{i}.post_attention_layernorm.weight", np.ones((hidden_dim,), dtype=np.float32)))
        items.append((f"model.layers.{i}.mlp.gate_proj.weight", rand((ffn_dim, hidden_dim))))
        items.append((f"model.layers.{i}.mlp.up_proj.weight", rand((ffn_dim, hidden_dim))))
        items.append((f"model.layers.{i}.mlp.down_proj.weight", rand((hidden_dim, ffn_dim))))
    items.append(("model.norm.weight", np.ones((hidden_dim,), dtype=np.float32)))
    # tie_word_embeddings = True for synthetic; lm_head.weight intentionally omitted.

    knot_config = {
        "arch": "qwen2",
        "hidden_dim": hidden_dim,
        "num_layers": num_layers,
        "num_heads": num_heads,
        "num_kv_heads": num_heads,
        "head_dim": hidden_dim // num_heads,
        "intermediate_size": ffn_dim,
        "vocab_size": vocab,
        "rms_norm_eps": 1e-6,
        "rope_theta": 10000.0,
        "tie_word_embeddings": True,
    }
    return items, knot_config


def _encode_synthetic(args) -> dict:
    items, knot_config = _make_synthetic_state(
        num_layers=args.syn_layers,
        hidden_dim=args.syn_hidden,
        ffn_dim=args.syn_ffn,
    )
    print(
        f"[synthetic] {len(items)} tensors; layers={knot_config['num_layers']} "
        f"hidden={knot_config['hidden_dim']} ffn={knot_config['intermediate_size']}"
    )
    return encode_state_dict(
        items=items,
        model_name=args.model_name or "synthetic",
        arch="qwen2",
        knot_config=knot_config,
        output_path=args.output,
        max_layers=args.max_layers,
        to_numpy=lambda x: x,  # already numpy
        tie_word_embeddings=True,
        rank=args.rank,
        sketch_rank=args.with_exclusion_sketch,
        sketch_output_path=args.sketch_output,
    )


# ─────────────────────────────────────────────────────────────────────────────
# CLI
# ─────────────────────────────────────────────────────────────────────────────


def parse_args(argv=None):
    p = argparse.ArgumentParser(description="Encode a real HF causal-LM into GKQ v2.")
    p.add_argument("--model", help="HF model id or local path (e.g. Qwen/Qwen2.5-0.5B-Instruct)")
    p.add_argument("--output", required=True, help="Output .knot path")
    p.add_argument("--model-name", default=None, help="Override model name stored in the header")
    p.add_argument("--max-layers", type=int, default=None,
                   help="Encode only the first N transformer layers (default: all)")
    p.add_argument("--rank", type=int, default=gkq.RANK_DEFAULT,
                   help=f"Spectral rank to retain per weight matrix (default: {gkq.RANK_DEFAULT})")
    p.add_argument("--synthetic", action="store_true",
                   help="Skip HF; build a small mock state_dict (good for sandbox testing)")
    p.add_argument("--syn-layers", type=int, default=3)
    p.add_argument("--syn-hidden", type=int, default=128)
    p.add_argument("--syn-ffn", type=int, default=256)
    # Phase A — Standing-Wave Mesh: emit a sibling rank-K sketches file.
    p.add_argument("--with-exclusion-sketch", type=int, default=None, metavar="RANK",
                   help=("Also write a sibling `<output>.sketches.knot` with rank-K "
                         "exclusion sketches for every 2D weight matrix (lm_head, "
                         "token_embd, all attn/FFN projections). Recommended rank: 32 "
                         "(per GKQHelixBandwidth.lean Section 7 — recall@K stays usable "
                         "down to rank-16 in the exclusion-filter regime)."))
    p.add_argument("--sketch-output", default=None,
                   help=("Override the sibling sketch output path (default: append "
                         "'.sketches.knot' to --output)."))
    return p.parse_args(argv)


def main(argv=None) -> int:
    args = parse_args(argv)
    if args.synthetic:
        summary = _encode_synthetic(args)
    else:
        if not args.model:
            print("ERROR: --model required unless --synthetic", file=sys.stderr)
            return 2
        summary = _encode_from_hf(args)
    _print_summary(summary)
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
